<?php
namespace Tests\Feature\Hr; use App\Models\HrLicense; use App\Models\LegalEntity; use App\Models\User; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Facades\DB; use Tests\TestCase;
class AssetPagesTest extends TestCase { use RefreshHrDatabase; public function test_asset_pages_render():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$u=User::factory()->create(['role_id'=>$role]);$this->actingAs($u);$t=LegalEntity::create(['user_id'=>$u->id,'name'=>'Zimmet','tax_number'=>'1212323232','is_active'=>true]);app(TenantContext::class)->set($t);HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$t->id,'user_id'=>$u->id,'employee_number'=>'ASTP','national_id_encrypted'=>'enc','national_id_hash'=>'asset-p','national_id_last_four'=>'0001','first_name'=>'Zimmet','last_name'=>'Sayfa','status'=>'active']);HrLicense::create(['legal_entity_id'=>$t->id,'module_key'=>'zimmet','is_active'=>true]);$this->get(route('hr.assets'))->assertOk()->assertSee('Zimmet Yönetimi');$this->get(route('hr.my-assets'))->assertOk()->assertSee('Zimmetlerim');} }
